INSERT INTO reviews (product_id, reviewer_name, reviewer_email, rating, title, body, status, fraud_score, fraud_reasons, verified_purchase, source, imported_from_judgeme, review_date) VALUES (NULL, 'Ar. Deyonte Lee', 'fisicasa@lyft.live', 5, 'Good Value for Minimalist Contemporary Design', 'I am an interior designer in singapore, we had an expat client in the Philippines who needed a minimalist contemporary design. I love the flexibility of materials available. We were given options of materials to choose from " fabric, microfiber or leather". In the end we chose microfiber due to the easiness of maintenance compared to real leather. We did not regret the purchase , we received the item in about 7 weeks from confirmation of materials and dimensions.', 'pending', 0, '[]'::jsonb, false, 'import', true, 'Sun Sep 17 2023 15:48:24 GMT+0800 (Philippine Standard Time)');
