INSERT INTO reviews (product_id, reviewer_name, reviewer_email, rating, title, body, status, fraud_score, fraud_reasons, verified_purchase, source, imported_from_judgeme, review_date) VALUES (223, ' Rosanna  Dueñas', 'hlq51496@eoopy.com', 5, 'The wait was well worth it, and the accent piece were just perfect. Highly recommended.', 'I just received my floor lamp yesterday, and it was well worth the wait. The base is very heavy, and the color is very true to the photos online! It was a perfect match for my desk and added a nice touch to my brand new office. They use bright white LED lighting, and you can tell the difference between when it''s dark outside and when it''s light outside. The vibe you get from just having the lamp on is gorgeous, and it provides a very comforting amount of light.', 'pending', 25, '["disposable_email_domain"]'::jsonb, false, 'import', true, 'Tue Sep 07 2021 10:05:05 GMT+0800 (Philippine Standard Time)');
