INSERT INTO reviews (product_id, reviewer_name, reviewer_email, rating, title, body, status, fraud_score, fraud_reasons, verified_purchase, source, imported_from_judgeme, review_date) VALUES (NULL, 'Jomayra Belloso', 'pcu18324@zwoho.com', 5, 'Solid, one-of-a-kind design, well worth the money!', 'I''m looking for a coffee table for a client''s newly remodelled living room, and I''m pleased I found this internet store through the recommendation of a friend who purchased furniture from here. I ordered this coffee table and it took more than a month to arrive, and I just got it yesterday. It is of excellent quality, solid, and has a distinctive design that exactly matches the style of my client''s living room. The shipping time is quite long, but it is well worth the wait, and the price is reasonable. Thank you; my customer loves it.', 'pending', 0, '[]'::jsonb, false, 'import', true, 'Wed Sep 01 2021 10:55:26 GMT+0800 (Philippine Standard Time)');
